func (c *current) onObject1(vals, last any) (any, error) {
	var slots []*SlotDecl
	for _, kv := range sliceOfAppend[Keyed[Node]](vals, last) {
		slots = append(slots, &SlotDecl{
			Name: &Symbol{
				Name: kv.Key,
				Loc:  kv.Value.GetSourceLocation(),
			},
			Value: kv.Value,
			Loc:   kv.Value.GetSourceLocation(),
		})
	}
	return &Object{
		Slots: slots,
		Loc:   c.Loc(),
	}, nil
}

